code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);

        int t = scanner.nextInt(); // Read number of test cases
        while (t--> 0) {
            int n = scanner.nextInt(); // Read the value of n
            int x = (int)(Math.log(n) / Math.log(2)); // Calculate log base 2 of n
            int ans = n - 1 - x; // Calculate the answer
            System.out.println(ans); // Print the result
        }

        scanner.close(); // Close the scanner
    }
}

code.JavaScript:
const readline = require('readline');

// Create an interface to read input
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

// Function to handle input and output
const main = () => {
    rl.on('line', (line) => {
        if (line === '') return; // Ignore empty lines
        if (!main.testCases) {
            // First line contains the number of test cases
            main.testCases = parseInt(line);
            main.currentCase = 0;
        } else {
            // Process each test case
            const n = parseInt(line);
            const x = Math.floor(Math.log2(n)); // Calculate log base 2 of n
            const ans = n - 1 - x; // Calculate the answer
            console.log(ans); // Output the answer
            main.currentCase++;
            // Close input after all test cases are processed
            if (main.currentCase === main.testCases) {
                rl.close();
            }
        }
    });
};

// Run the main function
main();
